1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Customer = { yearsWithMHPCO: number };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Array<Damage> };
5	type Step = { op: string; items?: Array<Item>; policy?: number; incident?: Incident };
6	type Scenario = { customer?: Customer; steps: Array<Step> };
7	
8	const DEDUCTIBLE_PER_DAMAGE = 100;
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
12	const CURSED_SURCHARGE_RATE = 0.5;
13	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
14	const HIGH_ENCHANTMENT_THRESHOLD = 5;
15	const LOYALTY_DISCOUNT_RATE = 0.2;
16	const LOYALTY_YEARS_THRESHOLD = 2;
17	const FOLLOWUP_DISCOUNT_RATE = 0.15;
18	
19	const BASE_PREMIUMS: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	function withFirstInsuranceSurcharge(basePremium: number): number {
29	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
30	}
31	
32	function surchargeIf(condition: boolean, basePremium: number, rate: number): number {
33	  return condition ? basePremium * rate : 0;
34	}
35	
36	function hasEnchantmentAtLeast(item: Item | undefined, threshold: number): boolean {
37	  return (item?.enchantment ?? 0) >= threshold;
38	}
39	
40	function quoteItem(item: Item): number {
41	  const basePremium = BASE_PREMIUMS[item.type];
42	  const cursedSurcharge = surchargeIf(item.cursed === true, basePremium, CURSED_SURCHARGE_RATE);
43	  const highEnchantmentSurcharge = surchargeIf(
44	    hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD),
45	    basePremium,
46	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
47	  );
48	  return withFirstInsuranceSurcharge(basePremium) + cursedSurcharge + highEnchantmentSurcharge;
49	}
50	
51	const COMPONENT_TYPES = ["rune", "moonstone"];
52	const BLOCK_OF_THREE_BASE = 60;
53	
54	function countByType(items: Array<Item>): Record<string, number> {
55	  const counts: Record<string, number> = {};
56	  for (const item of items) {
57	    counts[item.type] = (counts[item.type] ?? 0) + 1;
58	  }
59	  return counts;
60	}
61	
62	function isLoyalCustomer(customer: Customer | undefined): boolean {
63	  return (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
64	}
65	
66	function quoteItems(items: Array<Item>): { itemsPremium: number; sumOfBases: number } {
67	  const counts = countByType(items);
68	  let itemsPremium = 0;
69	  let sumOfBases = 0;
70	  const bundledTypes = new Set<string>();
71	
72	  for (const componentType of COMPONENT_TYPES) {
73	    if (counts[componentType] === 3) {
74	      itemsPremium += withFirstInsuranceSurcharge(BLOCK_OF_THREE_BASE);
75	      sumOfBases += BLOCK_OF_THREE_BASE;
76	      bundledTypes.add(componentType);
77	    }
78	  }
79	
80	  for (const item of items) {
81	    if (bundledTypes.has(item.type)) continue;
82	    itemsPremium += quoteItem(item);
83	    sumOfBases += BASE_PREMIUMS[item.type];
84	  }
85	
86	  return { itemsPremium, sumOfBases };
87	}
88	
89	type Policy = { items: Array<Item> };
90	
91	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
92	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
93	
94	function computeDamagePayout(damage: Damage, policy: Policy | undefined): number {
95	  const item = policy?.items.find((i) => i.type === damage.itemType);
96	  const reimbursableAmount = hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD)
97	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
98	    : damage.amount;
99	  return Math.max(0, reimbursableAmount - DEDUCTIBLE_PER_DAMAGE);
100	}
101	
102	function computePayout(incident: Incident | undefined, policy: Policy | undefined): number {
103	  const damages = incident?.damages ?? [];
104	  return damages.reduce((total, damage) => total + computeDamagePayout(damage, policy), 0);
105	}
106	
107	export function processScenario(
108	  scenario: unknown,
109	): { results: Array<{ premium?: number; payout?: number; remainingCap?: number }> } {
110	  const { customer, steps } = scenario as Scenario;
111	  const results: Array<{ premium?: number; payout?: number; remainingCap?: number }> = [];
112	  const policies = new Map<number, Policy>();
113	
114	  for (const [stepIndex, step] of steps.entries()) {
115	    if (step.op === "claim") {
116	      const policy = policies.get(step.policy ?? 0);
117	      results.push({ payout: computePayout(step.incident, policy) });
118	      continue;
119	    }
120	
121	    policies.set(stepIndex, { items: step.items ?? [] });
122	    let { itemsPremium, sumOfBases } = quoteItems(step.items ?? []);
123	
124	    if (isLoyalCustomer(customer)) {
125	      itemsPremium -= sumOfBases * LOYALTY_DISCOUNT_RATE;
126	    }
127	
128	    const isFollowUp = stepIndex >= 1;
129	    if (isFollowUp) {
130	      itemsPremium -= sumOfBases * FOLLOWUP_DISCOUNT_RATE;
131	    }
132	
133	    const premium = Math.ceil(itemsPremium + PROCESSING_FEE);
134	    results.push({ premium });
135	  }
136	
137	  return { results };
138	}
